package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  // Use the actual Gson JsonObject class for testing
  static class TestJsonObject extends JsonObject {
    @Override
    public JsonElement deepCopy() {
      return new TestJsonObject();
    }
  }

  static class TestJsonArray extends JsonArray {
    @Override
    public JsonElement deepCopy() {
      return new TestJsonArray();
    }
  }

  static class TestJsonPrimitive extends JsonPrimitive {
    @Override
    public JsonElement deepCopy() {
      return new TestJsonPrimitive();
    }
  }

  static class TestJsonNull extends JsonNull {
    @Override
    public JsonElement deepCopy() {
      return new TestJsonNull();
    }
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonObject_returnsTrue() {
    JsonElement jsonElement = new TestJsonObject();
    assertTrue(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonArray_returnsFalse() {
    JsonElement jsonElement = new TestJsonArray();
    assertFalse(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonPrimitive_returnsFalse() {
    JsonElement jsonElement = new TestJsonPrimitive();
    assertFalse(jsonElement.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonNull_returnsFalse() {
    JsonElement jsonElement = new TestJsonNull();
    assertFalse(jsonElement.isJsonObject());
  }
}
